import { Response, NextFunction } from 'express'
import { AuthRequest } from './auth.middleware'
import { subscriptionService } from '../services/subscription.service'

type CheckSubscriptionOptions = {
  featureKey?: string
  premiumOnly?: boolean
  trackUsage?: boolean
}

export const checkSubscription =
  (options: CheckSubscriptionOptions = {}) =>
  async (req: AuthRequest, res: Response, next: NextFunction): Promise<void> => {
    try {
      if (!req.user) {
        res.status(401).json({
          error: 'Authentication required.',
          code: 'AUTH_REQUIRED',
        })
        return
      }

      const featureKey = options.featureKey || 'company_reports'
      const access = await subscriptionService.assertFeatureAccess(req.user.id, featureKey)

      if (options.premiumOnly && access.plan !== 'PRO') {
        res.status(403).json({
          error: 'This feature requires an active Pro subscription.',
          code: 'PRO_REQUIRED',
        })
        return
      }

      if (options.trackUsage !== false) {
        let usageTracked = false
        res.on('finish', async () => {
          if (usageTracked || res.statusCode >= 400) {
            return
          }

          usageTracked = true
          try {
            await subscriptionService.incrementUsage(req.user!.id, featureKey)
          } catch {
            // Fail open on usage tracking so successful responses do not break.
          }
        })
      }

      next()
    } catch (error) {
      next(error)
    }
  }
